-- Create tables for "test_db"
GRANT ALL PRIVILEGES ON DATABASE test_db TO test_user;

\c test_db;

CREATE TABLE IF NOT EXISTS "__EFMigrationsHistory" (
    "MigrationId" character varying(150) NOT NULL,
    "ProductVersion" character varying(32) NOT NULL,
    CONSTRAINT "PK___EFMigrationsHistory" PRIMARY KEY ("MigrationId")
);

START TRANSACTION;
CREATE TABLE "Environments" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(100) NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_Environments" PRIMARY KEY ("Id")
);

CREATE TABLE "TestCases" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Code" character varying(200) NOT NULL,
    "IsActive" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TestCases" PRIMARY KEY ("Id")
);

CREATE TABLE "TestLevels" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Code" character varying(50) NOT NULL,
    "DisplayName" character varying(100) NOT NULL,
    "Description" character varying(2000) NOT NULL,
    "SortOrder" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    "Name" character varying(100) NOT NULL,
    CONSTRAINT "PK_TestLevels" PRIMARY KEY ("Id")
);

CREATE TABLE "TestStatuses" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Code" character varying(100) NOT NULL,
    "DisplayName" character varying(100) NOT NULL,
    "IsSuccess" boolean NOT NULL,
    "IsFailed" boolean NOT NULL,
    "IsSkipped" boolean NOT NULL,
    "IsExcluded" boolean NOT NULL,
    "IsInProgress" boolean NOT NULL,
    "IsTerminal" boolean NOT NULL,
    "SortOrder" integer NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TestStatuses" PRIMARY KEY ("Id")
);

CREATE TABLE "EnvironmentVersions" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Os" character varying(200) NOT NULL,
    "RunTime" character varying(2000) NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    "EnvironmentId" bigint NOT NULL,
    "VersionNumber" bigint NOT NULL,
    "IsLatest" boolean NOT NULL,
    CONSTRAINT "PK_EnvironmentVersions" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_EnvironmentVersions_Environments_EnvironmentId" FOREIGN KEY ("EnvironmentId") REFERENCES "Environments" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TestExecutions" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Revision" text NOT NULL,
    "EnvironmentId" bigint NOT NULL,
    "ExecutedAt" timestamp with time zone NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TestExecutions" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TestExecutions_Environments_EnvironmentId" FOREIGN KEY ("EnvironmentId") REFERENCES "Environments" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TestCaseVersions" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "Name" character varying(255) NOT NULL,
    "Description" character varying(2000) NOT NULL,
    "VersionNumber" bigint NOT NULL,
    "TestLevelId" bigint NOT NULL,
    "TestCaseId" bigint NOT NULL,
    "IsLatest" boolean NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TestCaseVersions" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TestCaseVersions_TestCases_TestCaseId" FOREIGN KEY ("TestCaseId") REFERENCES "TestCases" ("Id") ON DELETE CASCADE,
    CONSTRAINT "FK_TestCaseVersions_TestLevels_TestLevelId" FOREIGN KEY ("TestLevelId") REFERENCES "TestLevels" ("Id") ON DELETE RESTRICT
);

CREATE TABLE "TestExecutionItems" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "TestExecutionId" bigint NOT NULL,
    "ExecutedAt" timestamp with time zone NOT NULL,
    "EnvironmentId" bigint NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TestExecutionItems" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TestExecutionItems_EnvironmentVersions_EnvironmentId" FOREIGN KEY ("EnvironmentId") REFERENCES "EnvironmentVersions" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_TestExecutionItems_TestExecutions_TestExecutionId" FOREIGN KEY ("TestExecutionId") REFERENCES "TestExecutions" ("Id") ON DELETE CASCADE
);

CREATE TABLE "TestResults" (
    "Id" bigint GENERATED BY DEFAULT AS IDENTITY,
    "ActualResult" text NOT NULL,
    "TestExecutionItemId" bigint NOT NULL,
    "TestCaseVersionId" bigint NOT NULL,
    "Message" text,
    "StatusId" bigint NOT NULL,
    "ExecutedAt" timestamp with time zone NOT NULL,
    "CreatedAt" timestamp with time zone NOT NULL,
    "UpdatedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_TestResults" PRIMARY KEY ("Id"),
    CONSTRAINT "FK_TestResults_TestCaseVersions_TestCaseVersionId" FOREIGN KEY ("TestCaseVersionId") REFERENCES "TestCaseVersions" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_TestResults_TestExecutionItems_TestExecutionItemId" FOREIGN KEY ("TestExecutionItemId") REFERENCES "TestExecutionItems" ("Id") ON DELETE RESTRICT,
    CONSTRAINT "FK_TestResults_TestStatuses_StatusId" FOREIGN KEY ("StatusId") REFERENCES "TestStatuses" ("Id") ON DELETE RESTRICT
);

