CREATE UNIQUE INDEX "IX_Environments_Name" ON "Environments" ("Name");

CREATE INDEX "IX_EnvironmentVersions_EnvironmentId" ON "EnvironmentVersions" ("EnvironmentId");

CREATE UNIQUE INDEX "IX_EnvironmentVersions_Os_RunTime_EnvironmentId_VersionNumber" ON "EnvironmentVersions" ("Os", "RunTime", "EnvironmentId", "VersionNumber");

CREATE UNIQUE INDEX "IX_TestCases_Code" ON "TestCases" ("Code");

CREATE UNIQUE INDEX "IX_TestCaseVersions_Name_Description_TestLevelId_TestCaseId_Ve~" ON "TestCaseVersions" ("Name", "Description", "TestLevelId", "TestCaseId", "VersionNumber");

CREATE INDEX "IX_TestCaseVersions_TestCaseId" ON "TestCaseVersions" ("TestCaseId");

CREATE INDEX "IX_TestCaseVersions_TestLevelId" ON "TestCaseVersions" ("TestLevelId");

CREATE INDEX "IX_TestExecutionItems_EnvironmentId" ON "TestExecutionItems" ("EnvironmentId");

CREATE INDEX "IX_TestExecutionItems_TestExecutionId" ON "TestExecutionItems" ("TestExecutionId");

CREATE INDEX "IX_TestExecutions_EnvironmentId" ON "TestExecutions" ("EnvironmentId");

CREATE UNIQUE INDEX "IX_TestExecutions_Revision_EnvironmentId" ON "TestExecutions" ("Revision", "EnvironmentId");

CREATE INDEX "IX_TestResults_StatusId" ON "TestResults" ("StatusId");

CREATE INDEX "IX_TestResults_TestCaseVersionId" ON "TestResults" ("TestCaseVersionId");

CREATE UNIQUE INDEX "IX_TestResults_TestExecutionItemId_TestCaseVersionId_ExecutedAt" ON "TestResults" ("TestExecutionItemId", "TestCaseVersionId", "ExecutedAt");

SELECT setval(
    pg_get_serial_sequence('"TestLevels"', 'Id'),
    GREATEST(
        (SELECT MAX("Id") FROM "TestLevels") + 1,
        nextval(pg_get_serial_sequence('"TestLevels"', 'Id'))),
    false);
SELECT setval(
    pg_get_serial_sequence('"TestStatuses"', 'Id'),
    GREATEST(
        (SELECT MAX("Id") FROM "TestStatuses") + 1,
        nextval(pg_get_serial_sequence('"TestStatuses"', 'Id'))),
    false);

